parameters.jsCode:
const raw = $input.first().json;
const ctx = $('Merge Paths').first().json;

// Parse OpenAI response
let content;
try {
  const msg = raw.choices?.[0]?.message?.content || '{}';
  content = JSON.parse(msg);
} catch (e) {
  content = {
    blog_title:       ctx.episode_title + ' — Key Takeaways',
    blog_meta_description: 'Listen to ' + ctx.episode_title + ' from ' + ctx.show_name,
    blog_content:     '<h2>Episode Summary</h2><p>' + ctx.final_transcript.substring(0, 800) + '...</p>',
    blog_tags:        ['podcast', ctx.show_name, 'insights'],
    twitter_thread:   ['Check out our latest episode: ' + ctx.episode_title],
    linkedin_post:    'New episode of ' + ctx.show_name + ': ' + ctx.episode_title,
    email_snippet:    'We just released a new episode you need to hear.',
    tiktok_hooks:     ['You need to hear this...'],
    key_quotes:       [],
    episode_summary:  ctx.episode_title + ' — a must-listen episode.',
    seo_keywords:     ['podcast', ctx.show_name]
  };
}

// Compute token usage
const usage = raw.usage || {};
const cost  = ((usage.total_tokens || 0) / 1000 * 0.00015).toFixed(5);

return [{
  json: {
    ...ctx,
    ...content,
    tokens_used: usage.total_tokens || 0,
    estimated_cost_usd: parseFloat(cost),
    blog_tags_str: (content.blog_tags || []).join(', '),
    twitter_thread_str: (content.twitter_thread || []).join('\n\n'),
    tiktok_hooks_str: (content.tiktok_hooks || []).join(' | ')
  }
}];

